import { test, expect } from './fixtures';
import path from 'path';

test('Test tool magnifier', async ({ page, context, extensionId }) => {
    // Navigate to the demo page
    await page.goto(`chrome-extension://${extensionId}/popup.html#/app/tools/magnifier`);
    // Accept local storage usage
    await page.getByText("Accept").click();

    // submit input file
    await page.locator('[data-testid="magnifier-input"] input').fill('https://media.sudouest.fr/23190627/1200x600/macron.avif');
    await page.locator('[data-testid="magnifier-submit"]').click();

    // First assertion : is result presne
    await expect(page.locator('[data-testid="magnifier-results"]')).toBeVisible();

    // test cropper
    await page.locator('[data-testid="magnifier-open-cropper"]').click();
    await page.locator('[data-testid="magnifier-close-cropper"]').click();

    // test download
    const downloadPromise = page.waitForEvent('download');
    await page.locator('[data-testid="magnifier-download"]').click();
    const download = await downloadPromise;

    // Counting tabs before reverse search
    const countBefore = context.pages().length;

    // test inversed search
    await page.locator('[data-testid="magnifier-reversesearch"]').first().click();

    // counting tabs after reverse search
    await expect.poll(async () => {
        return context.pages().length;
    }).toBeGreaterThan(countBefore);

    // close the results
    await page.locator('[data-testid="magnifier-close"]').click();

    await expect(page.locator('[data-testid="magnifier-results"]')).toHaveCount(0);
});

test('Test tool metadata image', async ({ page, extensionId }) => {
  await page.goto(`chrome-extension://${extensionId}/popup.html#/app/tools/metadata_image`);
  await page.getByText("Accept").click();

  const filePath = path.resolve(__dirname, '../../tests-assets/test-metadata.jpg');

  await page.locator('input[type="file"]').setInputFiles(filePath);

  await page.locator('[data-testid="metadata-submit"]').click();

  await expect (page.locator('[data-testid="c2pa-result"]')).toBeVisible();
});

